import React from 'react';

const Layout = ({ children }) => {
  return (
    <div className="flex h-screen bg-black text-white overflow-hidden font-sans">
      {/* Sidebar */}
      <aside className="w-64 bg-black p-6 flex flex-col gap-4 border-r border-gray-800">
        <div className="text-2xl font-bold mb-8">Spotify 2.0</div>
        <nav className="flex flex-col gap-4 text-gray-400 font-semibold">
          <a href="#" className="hover:text-white transition">Inicio</a>
          <a href="#" className="hover:text-white transition">Buscar</a>
          <a href="#" className="hover:text-white transition">Tu Biblioteca</a>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 bg-gradient-to-b from-[#1e1e1e] to-[#121212] overflow-y-auto p-8">
        {children}
      </main>

      {/* Player (Barra Inferior) */}
      <footer className="fixed bottom-0 w-full h-24 bg-black border-t border-gray-800 p-4 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-gray-700 rounded-md shadow-lg"></div>
            <div>
                <p className="text-sm font-bold">Song Title</p>
                <p className="text-xs text-gray-400">Artist Name</p>
            </div>
        </div>
        <div className="text-white text-3xl"> ⏯️ </div>
        <div className="w-32 bg-gray-600 h-1 rounded-full"></div>
      </footer>
    </div>
  );
};

export default Layout;
